// Alertmanager sends an envelope with `alerts: [...]` (one or more).
// Emit one item per individual alert. Mark items where alertname triggers
// an auto-pause so the downstream node can act per SPEC §4.6.
const AUTO_PAUSE_ALERTS = new Set(['DeadLetterFlood']);

const body = $input.first().json.body || $input.first().json;
const alerts = Array.isArray(body.alerts) ? body.alerts : [body];

const items = alerts.map(a => {
  const labels = a.labels || {};
  const annotations = a.annotations || {};
  const startsAt = a.startsAt || '';
  const endsAtRaw = a.endsAt || '';
  const ends_at = (endsAtRaw && !endsAtRaw.startsWith('0001-')) ? endsAtRaw : '';
  const alertname = labels.alertname || 'unknown';
  const status = a.status || 'firing';
  return {
    json: {
      fingerprint:   a.fingerprint || '',
      alertname,
      severity:      labels.severity || 'unknown',
      status,
      starts_at:     startsAt,
      ends_at:       ends_at,
      generator_url: a.generatorURL || '',
      summary:       String(annotations.summary || '').slice(0, 500),
      description:   String(annotations.description || '').slice(0, 2000),
      labels_json:      JSON.stringify(labels),
      annotations_json: JSON.stringify(annotations),
      auto_pause:    AUTO_PAUSE_ALERTS.has(alertname) && status === 'firing'
    }
  };
});

if (items.length === 0) {
  return [{ json: { skipped: true, reason: 'no alerts in payload' } }];
}
return items;
